SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS `__migrationhistory`;
CREATE TABLE `__migrationhistory` (
  `MigrationId` varchar(150) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `ContextKey` varchar(300) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `Model` longblob NOT NULL,
  `ProductVersion` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  PRIMARY KEY (`MigrationId`,`ContextKey`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `accounts`;
CREATE TABLE `accounts` (
  `Id` int NOT NULL,
  `Username` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `PasswordHash` longtext,
  `IsActive` tinyint(1) NOT NULL,
  `EmployeeId` int NOT NULL,
  `PasswordResetTokenHash` longtext,
  `PasswordResetTokenExpiresAt` datetime DEFAULT NULL,
  PRIMARY KEY (`Id`),
  UNIQUE KEY `IX_Account_Username` (`Username`),
  KEY `IX_Id` (`Id`),
  CONSTRAINT `FK_Accounts_Employees_Id` FOREIGN KEY (`Id`) REFERENCES `employees` (`Id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `appointments`;
CREATE TABLE `appointments` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `PatientName` longtext NOT NULL,
  `PhoneNumber` longtext NOT NULL,
  `DentistId` int NOT NULL,
  `StartTime` datetime NOT NULL,
  `EndTime` datetime NOT NULL,
  `Status` int NOT NULL,
  `Notes` longtext,
  `CreatedById` int DEFAULT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_DentistId` (`DentistId`),
  KEY `IX_CreatedById` (`CreatedById`),
  CONSTRAINT `FK_Appointments_Employees_CreatedById` FOREIGN KEY (`CreatedById`) REFERENCES `employees` (`Id`),
  CONSTRAINT `FK_Appointments_Employees_DentistId` FOREIGN KEY (`DentistId`) REFERENCES `employees` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `dentistdegreesalarycoefficients`;
CREATE TABLE `dentistdegreesalarycoefficients` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `SalaryConfigurationId` int NOT NULL,
  `Degree` int NOT NULL,
  `Coefficient` decimal(18,2) NOT NULL,
  PRIMARY KEY (`Id`),
  UNIQUE KEY `IX_DentistDegreeSalaryCoefficient_Config_Degree` (`SalaryConfigurationId`,`Degree`),
  CONSTRAINT `FK_46f5f2377cfd4837b61875e16c9f24ff` FOREIGN KEY (`SalaryConfigurationId`) REFERENCES `salaryconfigurations` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `employees`;
CREATE TABLE `employees` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `FullName` longtext NOT NULL,
  `DateOfBirth` datetime NOT NULL,
  `Gender` int NOT NULL,
  `PhoneNumber` varchar(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `Email` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `Address` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `AvatarUrl` longtext,
  `Role` int NOT NULL,
  `StartDate` datetime NOT NULL,
  `ContractStatus` int NOT NULL,
  `Degree` int DEFAULT NULL,
  `ResignationDate` datetime DEFAULT NULL,
  PRIMARY KEY (`Id`),
  UNIQUE KEY `IX_Employee_PhoneNumber` (`PhoneNumber`),
  UNIQUE KEY `IX_Employee_Email` (`Email`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `employeeschedules`;
CREATE TABLE `employeeschedules` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `EmployeeId` int NOT NULL,
  `WorkShiftId` int NOT NULL,
  `ScheduleDate` date NOT NULL,
  `ShiftCoefficient` float DEFAULT NULL,
  `PatientCoefficient` float NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_EmployeeId` (`EmployeeId`),
  KEY `IX_WorkShiftId` (`WorkShiftId`),
  CONSTRAINT `FK_EmployeeSchedules_Employees_EmployeeId` FOREIGN KEY (`EmployeeId`) REFERENCES `employees` (`Id`),
  CONSTRAINT `FK_EmployeeSchedules_WorkShifts_WorkShiftId` FOREIGN KEY (`WorkShiftId`) REFERENCES `workshifts` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=3151 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `invoicedetails`;
CREATE TABLE `invoicedetails` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `InvoiceId` int NOT NULL,
  `ServiceId` int NOT NULL,
  `Quantity` int NOT NULL,
  `UnitPrice` decimal(18,2) NOT NULL,
  `Amount` decimal(18,2) NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_InvoiceId` (`InvoiceId`),
  KEY `IX_ServiceId` (`ServiceId`),
  CONSTRAINT `FK_InvoiceDetails_Invoices_InvoiceId` FOREIGN KEY (`InvoiceId`) REFERENCES `invoices` (`Id`),
  CONSTRAINT `FK_InvoiceDetails_Services_ServiceId` FOREIGN KEY (`ServiceId`) REFERENCES `services` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `invoicepayments`;
CREATE TABLE `invoicepayments` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `InvoiceId` int NOT NULL,
  `Amount` decimal(18,2) NOT NULL,
  `PaymentDate` datetime NOT NULL,
  `CreatedById` int NOT NULL,
  `Note` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_InvoiceId` (`InvoiceId`),
  KEY `IX_CreatedById` (`CreatedById`),
  CONSTRAINT `FK_InvoicePayments_Employees_CreatedById` FOREIGN KEY (`CreatedById`) REFERENCES `employees` (`Id`),
  CONSTRAINT `FK_InvoicePayments_Invoices_InvoiceId` FOREIGN KEY (`InvoiceId`) REFERENCES `invoices` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `invoices`;
CREATE TABLE `invoices` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `PatientId` int NOT NULL,
  `ExaminationId` int DEFAULT NULL,
  `CreatedDate` datetime NOT NULL,
  `CreatedById` int NOT NULL,
  `Notes` longtext,
  `TotalAmount` decimal(18,2) NOT NULL,
  `Status` int NOT NULL,
  `PaidAmount` decimal(18,2) NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_PatientId` (`PatientId`),
  KEY `IX_ExaminationId` (`ExaminationId`),
  KEY `IX_CreatedById` (`CreatedById`),
  CONSTRAINT `FK_Invoices_Employees_CreatedById` FOREIGN KEY (`CreatedById`) REFERENCES `employees` (`Id`),
  CONSTRAINT `FK_Invoices_PatientExaminations_ExaminationId` FOREIGN KEY (`ExaminationId`) REFERENCES `patientexaminations` (`Id`),
  CONSTRAINT `FK_Invoices_Patients_PatientId` FOREIGN KEY (`PatientId`) REFERENCES `patients` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `patientexaminations`;
CREATE TABLE `patientexaminations` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `PatientId` int NOT NULL,
  `AppointmentId` int DEFAULT NULL,
  `DentistId` int NOT NULL,
  `ExaminationDate` datetime NOT NULL,
  `Symptoms` longtext,
  `Diagnosis` longtext,
  `TreatmentPlan` longtext,
  `Prescription` longtext,
  `Notes` longtext,
  `Status` int NOT NULL,
  `DentalChartDetails` longtext,
  `ProposedServices` longtext,
  `ReExamDate` datetime DEFAULT NULL,
  `ManagerInterventionReason` longtext,
  PRIMARY KEY (`Id`),
  KEY `IX_PatientId` (`PatientId`),
  KEY `IX_AppointmentId` (`AppointmentId`),
  KEY `IX_DentistId` (`DentistId`),
  CONSTRAINT `FK_PatientExaminations_Appointments_AppointmentId` FOREIGN KEY (`AppointmentId`) REFERENCES `appointments` (`Id`),
  CONSTRAINT `FK_PatientExaminations_Employees_DentistId` FOREIGN KEY (`DentistId`) REFERENCES `employees` (`Id`),
  CONSTRAINT `FK_PatientExaminations_Patients_PatientId` FOREIGN KEY (`PatientId`) REFERENCES `patients` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `patients`;
CREATE TABLE `patients` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `FullName` longtext NOT NULL,
  `DateOfBirth` datetime NOT NULL,
  `Gender` int NOT NULL,
  `PhoneNumber` varchar(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `Email` longtext,
  `Address` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `salaryconfigurations`;
CREATE TABLE `salaryconfigurations` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `HourlyRate` decimal(18,2) NOT NULL,
  `DefaultShiftCoefficient` decimal(18,2) NOT NULL,
  `ReceptionistCoefficient` decimal(18,2) NOT NULL,
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `salaryformulasnapshots`;
CREATE TABLE `salaryformulasnapshots` (
  `Id` int NOT NULL,
  `SalaryRecordId` int NOT NULL,
  `Role` int NOT NULL,
  `BaseSalary` decimal(18,2) NOT NULL,
  `HourlyRate` decimal(18,2) NOT NULL,
  `Allowance` decimal(18,2) NOT NULL,
  `SnapshotDate` datetime NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_Id` (`Id`),
  CONSTRAINT `FK_SalaryFormulaSnapshots_SalaryRecords_Id` FOREIGN KEY (`Id`) REFERENCES `salaryrecords` (`Id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `salaryrecords`;
CREATE TABLE `salaryrecords` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `EmployeeId` int NOT NULL,
  `Month` int NOT NULL,
  `Year` int NOT NULL,
  `TotalHours` decimal(18,2) NOT NULL,
  `TotalAmount` decimal(18,2) NOT NULL,
  `IsFinalized` tinyint(1) NOT NULL,
  `FinalizedDate` datetime DEFAULT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_EmployeeId` (`EmployeeId`),
  CONSTRAINT `FK_SalaryRecords_Employees_EmployeeId` FOREIGN KEY (`EmployeeId`) REFERENCES `employees` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=282 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `servicecategories`;
CREATE TABLE `servicecategories` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `Name` longtext NOT NULL,
  `Description` longtext,
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `servicepricehistories`;
CREATE TABLE `servicepricehistories` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `ServiceId` int NOT NULL,
  `Price` decimal(18,2) NOT NULL,
  `EffectiveDate` datetime NOT NULL,
  `CreatedDate` datetime NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_ServiceId` (`ServiceId`),
  CONSTRAINT `FK_ServicePriceHistories_Services_ServiceId` FOREIGN KEY (`ServiceId`) REFERENCES `services` (`Id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `services`;
CREATE TABLE `services` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `Name` longtext NOT NULL,
  `Description` longtext,
  `CategoryId` int NOT NULL,
  `Price` decimal(18,2) NOT NULL,
  `IsActive` tinyint(1) NOT NULL,
  `IsMultiStage` tinyint(1) NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_CategoryId` (`CategoryId`),
  CONSTRAINT `FK_Services_ServiceCategories_CategoryId` FOREIGN KEY (`CategoryId`) REFERENCES `servicecategories` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `servicestages`;
CREATE TABLE `servicestages` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `ServiceId` int NOT NULL,
  `Name` longtext,
  `Order` int NOT NULL,
  `Percentage` decimal(18,2) NOT NULL,
  PRIMARY KEY (`Id`),
  KEY `IX_ServiceId` (`ServiceId`),
  CONSTRAINT `FK_ServiceStages_Services_ServiceId` FOREIGN KEY (`ServiceId`) REFERENCES `services` (`Id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `workshifts`;
CREATE TABLE `workshifts` (
  `Id` int NOT NULL AUTO_INCREMENT,
  `Name` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `StartTime` time NOT NULL,
  `EndTime` time NOT NULL,
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

